    @staticmethod
    def validate_field(table: str, field: str) -> bool:
        """Validate that field is in allowed list"""
        return field in SearchFilter.ALLOWED_FIELDS.get(table, [])
    
    @staticmethod
    def validate_operator(operator: str) -> bool:
        """Validate that operator is in allowed list"""
